#include <stdio.h>
#include <stdlib.h>
#define MAX 500

int max(int a, int b) { return a > b ? a : b; }

int minHours(int **grid, int n, int m) {
    int maxWealth = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            maxWealth = max(maxWealth, grid[i][j]);
        }
    }

    int hours = 0;
    int **newGrid = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        newGrid[i] = (int *)malloc(m * sizeof(int));
    }

    while (1) {
        int changed = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                newGrid[i][j] = grid[i][j];
                if (grid[i][j] < maxWealth) {
                    int maxNeighbor = 0;
                    for (int x = -1; x <= 1; x++) {
                        for (int y = -1; y <= 1; y++) {
                            int nx = i + x;
                            int ny = j + y;
                            if (nx >= 0 && nx < n && ny >= 0 && ny < m) {
                                maxNeighbor = max(maxNeighbor, grid[nx][ny]);
                            }
                        }
                    }
                    if (maxNeighbor > newGrid[i][j]) {
                        newGrid[i][j] = maxNeighbor;
                        changed = 1;
                    }
                }
            }
        }

        if (!changed) break;
        hours++;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                grid[i][j] = newGrid[i][j];
            }
        }
    }

    for (int i = 0; i < n; i++) {
        free(newGrid[i]);
    }
    free(newGrid);

    return hours;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int **grid = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            grid[i] = (int *)malloc(m * sizeof(int));
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        printf("%d\n", minHours(grid, n, m));
        for (int i = 0; i < n; i++) {
            free(grid[i]);
        }
        free(grid);
    }
    return 0;
}

