    m = len(grid[0])
    max_wealth = max(max(row) for row in grid)

    hours = 0
    while True:
        changed = False
        new_grid = [[cell for cell in row] for row in grid]
        for i in range(n):
            for j in range(m):
                if grid[i][j] < max_wealth:
                    max_neighbor = 0
                    for x in range(-1, 2):
                        for y in range(-1, 2):
